Event Start
LoadWWPContext.Call(&Context)
&FilCod = &Context.FilCod &EmpCod = &Context.EmpCod &TabCod = RetornatabelaFilial.udp(&EmpCod,&FilCod) &sdtProdutos.Clear() &IsSelect = false &ActionSelecione.FromImage(DDOMultiselOption)
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Grid.Rows = Page.Rows
JSDynamicFilters.Caption = '' &DynamicFiltersSelector1 = !'MARCOD' Do 'EnableDynamicFilters1' &DynamicFiltersSelector2 = !'MARCOD' Do 'EnableDynamicFilters2' &DynamicFiltersSelector3 = !'MARCOD' Do 'EnableDynamicFilters3'
AddDynamicFilters1.JSEvent('onclick', format(!"WWPDynFilterShow_AL('%1', 2, 0)", TableDynamicFilters.InternalName)) RemoveDynamicFilters1.JSEvent('onclick', format(!"WWPDynFilterHideLast_AL('%1', 3, 0)", TableDynamicFilters.InternalName)) AddDynamicFilters2.JSEvent('onclick', format(!"WWPDynFilterShow_AL('%1', 3, 0)", TableDynamicFilters.InternalName)) RemoveDynamicFilters2.JSEvent('onclick', format(!"WWPDynFilterHideLast_AL('%1', 3, 0)", TableDynamicFilters.InternalName)) RemoveDynamicFilters3.JSEvent('onclick', format(!"WWPDynFilterHideLast_AL('%1', 3, 0)", TableDynamicFilters.InternalName)) DDO_Grid.GridInternalName = Grid.InternalName Form.Caption = ' Cadastro de Produtos'
Do 'PrepareTransaction' Do 'LoadGridState' If &OrderedBy < 1 &OrderedBy = 1 Do 'SetDDOSortedStatus' EndIf &DDO_TitleSettingsIcons = GetWWPTitleSettingsIcons() GridPaginationBar.RowsPerPageSelectedValue = Grid.Rows
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event Refresh
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
LoadWWPContext.Call(&Context)
&DynamicFiltersOperator1.Clear() Do Case Case &DynamicFiltersSelector1 = !'MARCOD' &DynamicFiltersOperator1.AddItem(0, "<") &DynamicFiltersOperator1.AddItem(1, "=") &DynamicFiltersOperator1.AddItem(2, ">") Case &DynamicFiltersSelector1 = !'GRUPCOD' &DynamicFiltersOperator1.AddItem(0, "<") &DynamicFiltersOperator1.AddItem(1, "=") &DynamicFiltersOperator1.AddItem(2, ">") Case &DynamicFiltersSelector1 = !'TABPRC1' &DynamicFiltersOperator1.AddItem(0, "<") &DynamicFiltersOperator1.AddItem(1, "=") &DynamicFiltersOperator1.AddItem(2, ">") EndCase If &DynamicFiltersEnabled2 &DynamicFiltersOperator2.Clear() Do Case Case &DynamicFiltersSelector2 = !'MARCOD' &DynamicFiltersOperator2.AddItem(0, "<") &DynamicFiltersOperator2.AddItem(1, "=") &DynamicFiltersOperator2.AddItem(2, ">") Case &DynamicFiltersSelector2 = !'GRUPCOD' &DynamicFiltersOperator2.AddItem(0, "<") &DynamicFiltersOperator2.AddItem(1, "=") &DynamicFiltersOperator2.AddItem(2, ">") Case &DynamicFiltersSelector2 = !'TABPRC1' &DynamicFiltersOperator2.AddItem(0, "<") &DynamicFiltersOperator2.AddItem(1, "=") &DynamicFiltersOperator2.AddItem(2, ">") EndCase If &DynamicFiltersEnabled3 &DynamicFiltersOperator3.Clear() Do Case Case &DynamicFiltersSelector3 = !'MARCOD' &DynamicFiltersOperator3.AddItem(0, "<") &DynamicFiltersOperator3.AddItem(1, "=") &DynamicFiltersOperator3.AddItem(2, ">") Case &DynamicFiltersSelector3 = !'GRUPCOD' &DynamicFiltersOperator3.AddItem(0, "<") &DynamicFiltersOperator3.AddItem(1, "=") &DynamicFiltersOperator3.AddItem(2, ">") Case &DynamicFiltersSelector3 = !'TABPRC1' &DynamicFiltersOperator3.AddItem(0, "<") &DynamicFiltersOperator3.AddItem(1, "=") &DynamicFiltersOperator3.AddItem(2, ">") EndCase EndIf EndIf Do 'SaveGridState'
&GridCurrentPage = Grid.CurrentPage &GridPageCount = Grid.PageCount ProGraEstSdo.ColumnHeaderClass = !'WWColumn'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event GridPaginationBar.ChangePage
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do Case Case GridPaginationBar.SelectedPage = !'Previous' Grid.PreviousPage() Case GridPaginationBar.SelectedPage = !'Next' Grid.NextPage() Otherwise &PageToGo.FromString(GridPaginationBar.SelectedPage) Grid.GotoPage(&PageToGo) EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event GridPaginationBar.ChangeRowsPerPage
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
