/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event DDO_Grid.OnOptionClicked
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
Do Case Case DDO_Grid.ActiveEventKey = !'<#OrderASC#>' OR DDO_Grid.ActiveEventKey = !'<#OrderDSC#>' &OrderedBy.FromString(DDO_Grid.SelectedValue_get) &OrderedDsc = iif(DDO_Grid.ActiveEventKey = !'<#OrderDSC#>', true, false) Do 'SetDDOSortedStatus' Grid.FirstPage() EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndEvent
Event Grid.Load
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ActionSelecione.FromImage(DDOMultiselSelOption) &ActionSelecione.TooltipText = ""
Do Case Case ProGraEstSdo > 0 ProGraEstSdo.ColumnClass = !'WWColumn WWColumnSuccess WWColumnSuccessSingleCell' Case ProGraEstSdo <= 0 ProGraEstSdo.ColumnClass = !'WWColumn WWColumnDanger WWColumnDangerSingleCell' Otherwise ProGraEstSdo.ColumnClass = 'WWColumn' EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
&ActionSelecione.FromImage(DDOMultiselOption) if &IsSelect = true &ActionSelecione.FromImage(DDOMultiselSelOption) Endif
EndEvent
