Sub 'SetDDOSortedStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
DDO_Grid.SortedStatus = &OrderedBy.ToString().Trim() + !':' + iif(&OrderedDsc, !'DSC', !'ASC')
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'EnableDynamicFilters1'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&MarCod1.Visible = False &GrupCod1.Visible = False &TabPrc11.Visible = False &DynamicFiltersOperator1.Visible = False Do Case Case &DynamicFiltersSelector1 = !'MARCOD' &MarCod1.Visible = True &DynamicFiltersOperator1.Visible = True Case &DynamicFiltersSelector1 = !'GRUPCOD' &GrupCod1.Visible = True &DynamicFiltersOperator1.Visible = True Case &DynamicFiltersSelector1 = !'TABPRC1' &TabPrc11.Visible = True &DynamicFiltersOperator1.Visible = True EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'EnableDynamicFilters2'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&MarCod2.Visible = False &GrupCod2.Visible = False &TabPrc12.Visible = False &DynamicFiltersOperator2.Visible = False Do Case Case &DynamicFiltersSelector2 = !'MARCOD' &MarCod2.Visible = True &DynamicFiltersOperator2.Visible = True Case &DynamicFiltersSelector2 = !'GRUPCOD' &GrupCod2.Visible = True &DynamicFiltersOperator2.Visible = True Case &DynamicFiltersSelector2 = !'TABPRC1' &TabPrc12.Visible = True &DynamicFiltersOperator2.Visible = True EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
