Sub 'EnableDynamicFilters3'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&MarCod3.Visible = False &GrupCod3.Visible = False &TabPrc13.Visible = False &DynamicFiltersOperator3.Visible = False Do Case Case &DynamicFiltersSelector3 = !'MARCOD' &MarCod3.Visible = True &DynamicFiltersOperator3.Visible = True Case &DynamicFiltersSelector3 = !'GRUPCOD' &GrupCod3.Visible = True &DynamicFiltersOperator3.Visible = True Case &DynamicFiltersSelector3 = !'TABPRC1' &TabPrc13.Visible = True &DynamicFiltersOperator3.Visible = True EndCase
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'ResetDynFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&DynamicFiltersEnabled2 = False &DynamicFiltersSelector2 = !'MARCOD' &DynamicFiltersOperator2 = 0 &MarCod2.SetEmpty() Do 'EnableDynamicFilters2'
&DynamicFiltersEnabled3 = False &DynamicFiltersSelector3 = !'MARCOD' &DynamicFiltersOperator3 = 0 &MarCod3.SetEmpty() Do 'EnableDynamicFilters3'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(&PgmName + !"GridState") = !"" &GridState.FromXml(LoadGridState.Udp(&PgmName + !"GridState")) Else &GridState.FromXml(&Session.Get(&PgmName + !"GridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc Do 'SetDDOSortedStatus'
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"PROCOD" &ProCod.FromString(&GridStateFilterValue.Value) &ProCod_To.FromString(&GridStateFilterValue.ValueTo) Case &GridStateFilterValue.Name = !"TABCOD" &TabCod.FromString(&GridStateFilterValue.Value) EndCase EndFor Do 'LoadDynFiltersState' If not &GridState.PageSize.Trim().IsEmpty() Grid.Rows = &GridState.PageSize.ToNumeric() EndIf Grid.CurrentPage = &GridState.CurrentPage
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadDynFiltersState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
AddDynamicFilters1.Visible = True RemoveDynamicFilters1.Visible = False AddDynamicFilters2.Visible = True RemoveDynamicFilters2.Visible = False
If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'MARCOD' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &MarCod1.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector1 = !'GRUPCOD' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &GrupCod1.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector1 = !'TABPRC1' &DynamicFiltersOperator1 = &GridStateDynamicFilter.Operator &TabPrc11.FromString(&GridStateDynamicFilter.Value) EndCase Do 'EnableDynamicFilters1' If &GridState.DynamicFilters.Count >= 2 JSDynamicFilters.Caption = !'<script type="text/javascript">$(document).ready(function() {' JSDynamicFilters.Caption += format(!"WWPDynFilterShow_AL('%1', 2, 0);", TableDynamicFilters.InternalName) AddDynamicFilters1.Visible = False RemoveDynamicFilters1.Visible = True &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'MARCOD' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &MarCod2.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector2 = !'GRUPCOD' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &GrupCod2.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector2 = !'TABPRC1' &DynamicFiltersOperator2 = &GridStateDynamicFilter.Operator &TabPrc12.FromString(&GridStateDynamicFilter.Value) EndCase Do 'EnableDynamicFilters2' If &GridState.DynamicFilters.Count >= 3 JSDynamicFilters.Caption += format(!"WWPDynFilterShow_AL('%1', 3, 0);", TableDynamicFilters.InternalName) AddDynamicFilters2.Visible = False RemoveDynamicFilters2.Visible = True &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'MARCOD' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &MarCod3.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector3 = !'GRUPCOD' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &GrupCod3.FromString(&GridStateDynamicFilter.Value) Case &DynamicFiltersSelector3 = !'TABPRC1' &DynamicFiltersOperator3 = &GridStateDynamicFilter.Operator &TabPrc13.FromString(&GridStateDynamicFilter.Value) EndCase Do 'EnableDynamicFilters3' EndIf JSDynamicFilters.Caption += !'});</script>' EndIf EndIf If &DynamicFiltersRemoving JSDynamicFilters.Caption = '' EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'SaveGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&GridState.FromXml(&Session.Get(&PgmName + !"GridState"))
// Save grid state in session. &GridState.OrderedBy = &OrderedBy &GridState.OrderedDsc = &OrderedDsc &GridState.FilterValues.Clear() WWP_GridStateAddFilterValue(&GridState, !"PROCOD", "", not (&ProCod.IsEmpty() AND &ProCod_To.IsEmpty()), 0, &ProCod.ToString().Trim(), &ProCod_To.ToString().Trim()) WWP_GridStateAddFilterValue(&GridState, !"TABCOD", "", not &TabCod.IsEmpty(), 0, &TabCod, '')
Do 'SaveDynFiltersState'
&GridState.PageSize = str(Grid.Rows) &GridState.CurrentPage = Grid.CurrentPage SaveGridState.Call(&PgmName + !"GridState", &GridState.ToXml())
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'SaveDynFiltersState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&GridState.DynamicFilters.Clear() If not &DynamicFiltersIgnoreFirst &GridStateDynamicFilter = new() &GridStateDynamicFilter.Selected = &DynamicFiltersSelector1 Do Case Case &DynamicFiltersSelector1 = !'MARCOD' AND not &MarCod1.IsEmpty() &GridStateDynamicFilter.Value = &MarCod1.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator1 Case &DynamicFiltersSelector1 = !'GRUPCOD' AND not &GrupCod1.IsEmpty() &GridStateDynamicFilter.Value = &GrupCod1.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator1 Case &DynamicFiltersSelector1 = !'TABPRC1' AND not &TabPrc11.IsEmpty() &GridStateDynamicFilter.Value = &TabPrc11.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator1 EndCase If &DynamicFiltersRemoving OR not &GridStateDynamicFilter.Value.IsEmpty() &GridState.DynamicFilters.Add(&GridStateDynamicFilter) EndIf EndIf If &DynamicFiltersEnabled2 &GridStateDynamicFilter = new() &GridStateDynamicFilter.Selected = &DynamicFiltersSelector2 Do Case Case &DynamicFiltersSelector2 = !'MARCOD' AND not &MarCod2.IsEmpty() &GridStateDynamicFilter.Value = &MarCod2.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator2 Case &DynamicFiltersSelector2 = !'GRUPCOD' AND not &GrupCod2.IsEmpty() &GridStateDynamicFilter.Value = &GrupCod2.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator2 Case &DynamicFiltersSelector2 = !'TABPRC1' AND not &TabPrc12.IsEmpty() &GridStateDynamicFilter.Value = &TabPrc12.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator2 EndCase If &DynamicFiltersRemoving OR not &GridStateDynamicFilter.Value.IsEmpty() &GridState.DynamicFilters.Add(&GridStateDynamicFilter) EndIf EndIf If &DynamicFiltersEnabled3 &GridStateDynamicFilter = new() &GridStateDynamicFilter.Selected = &DynamicFiltersSelector3 Do Case Case &DynamicFiltersSelector3 = !'MARCOD' AND not &MarCod3.IsEmpty() &GridStateDynamicFilter.Value = &MarCod3.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator3 Case &DynamicFiltersSelector3 = !'GRUPCOD' AND not &GrupCod3.IsEmpty() &GridStateDynamicFilter.Value = &GrupCod3.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator3 Case &DynamicFiltersSelector3 = !'TABPRC1' AND not &TabPrc13.IsEmpty() &GridStateDynamicFilter.Value = &TabPrc13.ToString() &GridStateDynamicFilter.Operator = &DynamicFiltersOperator3 EndCase If &DynamicFiltersRemoving OR not &GridStateDynamicFilter.Value.IsEmpty() &GridState.DynamicFilters.Add(&GridStateDynamicFilter) EndIf EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'PrepareTransaction'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&TrnContext = new() &TrnContext.CallerObject = &Pgmname &TrnContext.CallerOnDelete = True &TrnContext.CallerURL = &HTTPRequest.ScriptName + !"?" + &HTTPRequest.QueryString &TrnContext.TransactionName = !"Produto"
&Session.Set(!"TrnContext", &TrnContext.ToXml())
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Event &ActionSelecione.Click
if &IsSelect = true &ActionSelecione.FromImage(DDOMultiselOption) &IsSelect = false Else &ActionSelecione.FromImage(DDOMultiselSelOption) &IsSelect = true Endif
If &CreDupSel = True &sdtProdutosItem = new() &sdtProdutosItem.ProCod = ProCod &sdtProdutos.Add(&sdtProdutosItem) else For &sdtProdutosItem in &sdtProdutos If &sdtProdutosItem.ProCod = ProCod &Index = &sdtProdutos.IndexOf(&sdtProdutosItem) &sdtProdutos.Remove(&Index) Exit EndIF EndFor EndIf
EndEvent
